 * Tạo một tệp JSON mới dựa trên thông tin cấu trúc mạng có ID tương ứng với tham số TopologyId
 * @param {string} TopologyId - ID của cấu trúc mạng
 */
function writeJSON(TopologyId)
{
    // Khai báo biến mới để lưu trữ tệp JSON
    let newFile = null

    // Khai báo biến mới để lưu trữ dữ liệu
    let data = null

    // Duyệt qua mảng cấu trúc mạng
