        Self {
            line_width: 100,
            indent_size: 2,
            indent_style: IndentStyle::Spaces,
            keyword_case: KeywordCase::default(),
            constant_case: KeywordCase::default(),
            type_case: KeywordCase::default(),
        }
    }
}

fn main() {
    let my_struct = MyStruct::default();
    println!("line_width: {}", my_struct.line_width);
    println!("indent_size: {}", my_struct.indent_size);
    println!("indent_style: {:?}", my_struct.indent_style);
    println!("keyword_case: {:?}", my_struct.keyword_case);
    println!("constant_case: {:?}", my_struct.constant_case);
    println!("type_case: {:?}", my_struct.type_case);
}
```

